'use client'

import { useEffect, useState } from 'react'
import { Moon, Sun } from 'lucide-react'

export function ThemeToggle() {
  const [isDark, setIsDark] = useState(() => {
    if (typeof document === 'undefined') return false
    return document.documentElement.classList.contains('dark')
  })

  useEffect(() => {
    const syncTheme = () => {
      setIsDark(document.documentElement.classList.contains('dark'))
    }

    const frame = window.requestAnimationFrame(syncTheme)
    const observer = new MutationObserver(syncTheme)
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ['class'] })

    return () => {
      window.cancelAnimationFrame(frame)
      observer.disconnect()
    }
  }, [])

  const toggleTheme = () => {
    const html = document.documentElement

    if (isDark) {
      html.classList.remove('dark')
      localStorage.setItem('theme', 'light')
      return
    }

    html.classList.add('dark')
    localStorage.setItem('theme', 'dark')
  }

  return (
    <button
      onClick={toggleTheme}
      className="rounded-2xl border border-border/70 bg-background/80 p-2.5 shadow-[0_14px_35px_-28px_rgba(15,23,42,0.35)] transition-all duration-200 hover:-translate-y-0.5 hover:bg-hover"
      aria-label="Toggle theme"
    >
      {isDark ? <Sun className="h-5 w-5 text-foreground" /> : <Moon className="h-5 w-5 text-foreground" />}
    </button>
  )
}
